/* doc-css — Shared styles for doc rendering */

/* Item references */
.hob-item-ref {
  color: var(--color-primary, #0066cc);
  background: oklch(98.5% 0.01 250);
  text-decoration: none !important;
  border-bottom: 1.5px dashed oklch(75% 0.06 250);
  cursor: pointer;
  font-family: inherit;
  font-size: inherit;
}

.hob-item-ref:hover {
  background: oklch(96% 0.02 250);
  border-bottom-color: var(--color-primary, #0066cc);
}
